102	// TestBeadsByProject_ConcurrentQueriesAndUpdates covers ddx-9ce6842a AC §6:
103	// N concurrent readers + writers interleaved without torn reads or panics.
104	func TestBeadsByProject_ConcurrentQueriesAndUpdates(t *testing.T) {
105		t.Setenv("XDG_DATA_HOME", t.TempDir())
106		t.Setenv("DDX_NODE_NAME", "stale-read-concurrent")
107	
108		projectPath := filepath.Join(t.TempDir(), "project")
109		store := bead.NewStore(filepath.Join(projectPath, ddxroot.DirName))
110		if err := store.Init(); err != nil {
111			t.Fatalf("init: %v", err)
112		}
113		base := time.Date(2026, 1, 1, 0, 0, 0, 0, time.UTC)
114		beads := make([]bead.Bead, 0, 20)
115		for i := 0; i < 20; i++ {
116			beads = append(beads, bead.Bead{
117				ID:        fmt.Sprintf("ddx-concur-%03d", i),
118				Title:     "concurrent fixture",
119				Status:    bead.StatusOpen,
120				Priority:  bead.DefaultPriority,
121				IssueType: bead.DefaultType,
122				CreatedAt: base,
123				UpdatedAt: base,
124			})
125		}
126		if err := store.WriteAll(beads); err != nil {
127			t.Fatalf("write: %v", err)
128		}
129	
130		srv := New(":0", projectPath)
131		t.Cleanup(func() { _ = srv.Shutdown() })
132		projects := srv.state.GetProjects()
133		if len(projects) != 1 {
134			t.Fatalf("setup: want 1 project, got %d", len(projects))
135		}
136		projectID := projects[0].ID
137		handler := srv.Handler()
138	
139		const readers = 8
140		const iterations = 15
141		errs := make(chan error, readers*iterations*2)
142		var wg sync.WaitGroup
143		// Writers: keep renaming bead 000 through a known sequence.
144		for w := 0; w < 2; w++ {
145			wg.Add(1)
146			go func(w int) {
147				defer wg.Done()
148				for i := 0; i < iterations; i++ {
149					title := fmt.Sprintf("w%02d-i%03d", w, i)
150					if err := store.Update("ddx-concur-000", func(b *bead.Bead) {
151						b.Title = title
152					}); err != nil {
153						errs <- fmt.Errorf("writer %d iter %d: %w", w, i, err)
154						return
155					}
156				}
157			}(w)
158		}
159		// Readers: hammer the list resolver and parse every response.
160		for r := 0; r < readers; r++ {
161			wg.Add(1)
162			go func(r int) {
163				defer wg.Done()
164				query := fmt.Sprintf(`{ beadsByProject(projectID: %q, first: 50) { edges { node { id title } } } }`, projectID)
165				for i := 0; i < iterations; i++ {
166					raw, err := postStaleList(handler, query)
167					if err != nil {
168						errs <- fmt.Errorf("reader %d iter %d: %w", r, i, err)
169						return
170					}
171					// Shape sanity check — the whole beads list must be present
172					// even while a writer is mutating bead 000. A torn read would
173					// manifest as either a missing "edges" key or a 500.
174					if !bytes.Contains(raw, []byte(`"edges"`)) {
175						errs <- fmt.Errorf("reader %d iter %d: malformed body: %s", r, i, string(raw))
176						return
177					}
178					if !bytes.Contains(raw, []byte("ddx-concur-000")) {
179						errs <- fmt.Errorf("reader %d iter %d: bead 000 missing from response", r, i)
180						return
181					}
182				}
183			}(r)
184		}
185		wg.Wait()
186		close(errs)
187		for err := range errs {
188			if err != nil {
189				t.Fatal(err)
190			}
191		}
192		_ = strings.TrimSpace // keep import in case reader evolves
193	}
