38	// TestOperatorCancel_Idempotent: a second cancel on a bead whose worker has
39	// already honored the first is a silent no-op (status 200, no error). The
40	// honored marker remains set.
41	func TestOperatorCancel_Idempotent(t *testing.T) {
42		dir := setupTestDir(t)
43		srv := New(":0", dir)
44		store := bead.NewStore(filepath.Join(dir, ddxroot.DirName))
45	
46		// First cancel.
47		req := httptest.NewRequest("POST", "/api/beads/bx-001/cancel", nil)
48		req.RemoteAddr = "127.0.0.1:12345"
49		w := httptest.NewRecorder()
50		srv.Handler().ServeHTTP(w, req)
51		if w.Code != http.StatusOK {
52			t.Fatalf("first cancel: expected 200, got %d", w.Code)
53		}
54	
55		// Simulate the worker honoring it.
56		if err := store.MarkCancelHonored("bx-001"); err != nil {
57			t.Fatalf("MarkCancelHonored: %v", err)
58		}
59	
60		// Second cancel should be a silent success — no new cancel-requested
61		// marker, honored stays set.
62		req2 := httptest.NewRequest("POST", "/api/beads/bx-001/cancel", nil)
63		req2.RemoteAddr = "127.0.0.1:12345"
64		w2 := httptest.NewRecorder()
65		srv.Handler().ServeHTTP(w2, req2)
66		if w2.Code != http.StatusOK {
67			t.Fatalf("second cancel: expected 200, got %d: %s", w2.Code, w2.Body.String())
68		}
69	
70		b, err := store.Get("bx-001")
71		if err != nil {
72			t.Fatalf("Get: %v", err)
73		}
74		if got := b.Extra[bead.ExtraCancelHonored]; got != true {
75			t.Fatalf("expected cancel-honored=true after worker ack, got %v", got)
76		}
77	}
